# Slack notification steps (in deploy-prod job or separate notify job):

# Success notification:
- name: Notify Slack — Success
  if: success()
  uses: slackapi/slack-github-action@v1
  with:
    payload: |
      {
        'text': ':white_check_mark: *Payment Service deployed to PRODUCTION*',
        'blocks': [
          {
            'type': 'section',
            'text': {
              'type': 'mrkdwn',
              'text': ':white_check_mark: *Payment Service deployed to Production*\nCommit: `${{ github.sha }}`\nBy: @${{ github.actor }}\n<${{ github.server_url }}/${{ github.repository }}/actions/runs/${{ github.run_id }}|View Run>'
            }
          }
        ]
      }
  env:
    SLACK_WEBHOOK_URL: ${{ secrets.SLACK_PAYMENTS_WEBHOOK }}
    SLACK_WEBHOOK_TYPE: INCOMING_WEBHOOK

# Failure notification (with rollback context):
- name: Notify Slack — Failure
  if: failure()
  uses: slackapi/slack-github-action@v1
  with:
    payload: |
      {
        'text': ':x: *PRODUCTION DEPLOY FAILED — Rollback initiated*',
        'blocks': [
          {
            'type': 'section',
            'text': {
              'type': 'mrkdwn',
              'text': ':x: *FAILED: Payment Service production deploy*\nCommit: `${{ github.sha }}`\nAuthor: @${{ github.actor }}\n*Rollback in progress...*\n<${{ github.server_url }}/${{ github.repository }}/actions/runs/${{ github.run_id }}|View Failure Details>'
            }
          }
        ]
      }
  env:
    SLACK_WEBHOOK_URL: ${{ secrets.SLACK_PAYMENTS_WEBHOOK }}
    SLACK_WEBHOOK_TYPE: INCOMING_WEBHOOK

