// Java tests to validate CI health:
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class CICDValidationTest {
    @Autowired WebTestClient wc;
    @Autowired MeterRegistry reg;

    @Test void healthEndpoint_returns2xx() {
        // Validates: Spring Boot starts cleanly in CI environment
        // GitHub Actions: also runs with H2 in-memory DB
        wc.get().uri('/actuator/health')
          .exchange()
          .expectStatus().is2xxSuccessful()
          .expectBody().jsonPath('$.status').isEqualTo('UP');
    }

    @Test void businessMetric_canBeCreated() {
        // Validates: Micrometer is configured and working
        Counter c = reg.counter('cicd.validation.test', 'env', 'ci');
        c.increment();
        assertEquals(1.0, c.count(), 0.01);

        // In real CI: this test + build passing → docker build → push to GHCR
        // The exact same image runs this test (in container) → then deployed
        System.out.println('[CI] All validation tests passed — safe to deploy!');
    }
}
